5	/**
6	 * Ranking order of the 1974/75 English First Division (docs/rules-research.md
7	 * sections 3-5 and 8): points descending, then goal average (goals for divided
8	 * by goals against - not goal difference) descending, then goals for
9	 * descending, then team name ascending. The alphabetical fallback is an
10	 * application-level decision for deterministic output, not a historical rule.
11	 *
12	 * <p>Goal averages are compared by cross-multiplication in {@code long}
13	 * arithmetic; no floating point is used anywhere. Zero goals against is
14	 * handled explicitly: with goals scored it ranks above every finite average,
15	 * and a 0/0 goal record is treated as goal average zero.
16	 *
17	 * <p>Precondition: goal counts are non-negative. Cross-multiplication is not
18	 * a valid total order over negative values; input validation (rules-research
19	 * section 9) must reject negative scores before records reach this comparator.
20	 */
21	public final class StandingsRanking implements Comparator<TeamRecord> {
22	
23	    @Override
24	    public int compare(TeamRecord left, TeamRecord right) {
25	        int byPoints = Integer.compare(right.points(), left.points());
26	        if (byPoints != 0) {
27	            return byPoints;
28	        }
29	        int byGoalAverage = compareByGoalAverageDescending(left, right);
30	        if (byGoalAverage != 0) {
31	            return byGoalAverage;
32	        }
33	        int byGoalsFor = Integer.compare(right.goalsFor(), left.goalsFor());
34	        if (byGoalsFor != 0) {
35	            return byGoalsFor;
36	        }
37	        return left.team().compareTo(right.team());
38	    }
39	
40	    private static int compareByGoalAverageDescending(TeamRecord left, TeamRecord right) {
41	        boolean leftInfinite = isInfiniteAverage(left);
42	        boolean rightInfinite = isInfiniteAverage(right);
43	        if (leftInfinite || rightInfinite) {
44	            return Boolean.compare(rightInfinite, leftInfinite);
45	        }
46	        return Long.compare(crossProduct(right, left), crossProduct(left, right));
47	    }
48	
49	    private static boolean isInfiniteAverage(TeamRecord record) {
50	        return record.goalsAgainst() == 0 && record.goalsFor() > 0;
51	    }
52	
53	    /** left.goalsFor x right.goalsAgainst, with a 0/0 record normalised to 0/1. */
54	    private static long crossProduct(TeamRecord left, TeamRecord right) {
55	        long rightAgainst = right.goalsAgainst() == 0 ? 1 : right.goalsAgainst();
56	        return left.goalsFor() * rightAgainst;
57	    }
58	}
